import pickle
def cluster_counts_mod(mapping, sorted_clusters, codeword_length):
    cluster_counts_mod = {i: 0 for i in range(codeword_length)}
    for cluster, index in mapping.items():
            cluster_counts_mod[ cluster % codeword_length] += sorted_clusters[index]
    print("Cluster counts mod 128 method 1: ", cluster_counts_mod)
    cluster_counts_zigzag = {i: 0 for i in range(codeword_length)}
    # zigzag metho
    direction = 1
    new_index = 0
    for cluster, index in mapping.items():
        cluster_counts_zigzag[new_index] += sorted_clusters[index]
        if direction == 1:
            new_index += 1
        else:
            new_index -= 1
        if new_index == codeword_length:
            new_index = codeword_length - 1
            direction = -1
        if new_index == -1:
            new_index = 0
            direction = 1

    print("Cluster counts mod 128 method 2: ", cluster_counts_zigzag)

